    "modular-forms": {
      "topic": "modular-forms",
      "title": "Modular forms",
      "page": "modular-forms.html",
      "concepts": [
        {
          "id": "lattices-in-C",
          "title": "Lattices in C",
          "anchor": "lattices-in-C",
          "prereqs": [
            "complex-numbers"
          ],
          "blurb": "A lattice $\\Lambda \\subset \\mathbb{C}$ is a discrete subgroup of rank 2: $\\Lambda = \\mathbb{Z}\\omega_1 + \\mathbb{Z}\\omega_2$ with $\\omega_2/\\omega_1 \\notin \\mathbb{R}$. The same lattice has many bases — exactly the bases related by an $\\mathrm{SL}_2(\\mathbb{Z})$ change of coordinates — which is why modular forms are functions on lattices, or equivalently, $\\mathrm{SL}_2(\\mathbb{Z})$-equivariant functions of the basis ratio $\\tau = \\omega_2/\\omega_1 \\in \\mathbb{H}$."
        },
        {
          "id": "sl2z-on-H",
          "title": "SL2(Z) action on the upper half-plane",
          "anchor": "sl2z",
          "prereqs": [
            "lattices-in-C",
            "sl2r-action-on-H"
          ],
          "blurb": "Matrices in SL2(Z) act by Möbius transformations and generate the modular equivalence relation on H."
        },
        {
          "id": "modular-form-definition",
          "title": "Definition of modular forms",
          "anchor": "forms",
          "prereqs": [
            "sl2z-on-H"
          ],
          "blurb": "A weight-k modular form is holomorphic on H, transforms by (cτ+d)^k under SL2(Z), and is holomorphic at infinity."
        },
        {
          "id": "eisenstein-series-mf",
          "title": "Eisenstein series",
          "anchor": "eisen",
          "prereqs": [
            "modular-form-definition"
          ],
          "blurb": "The series E4 and E6 are explicit modular forms that generate much of the level-1 ring structure."
        },
        {
          "id": "q-expansions-mf",
          "title": "q-expansions and arithmetic data",
          "anchor": "qexp",
          "prereqs": [
            "modular-form-definition",
            "eisenstein-series-mf"
          ],
          "blurb": "Fourier expansions f(τ)=Σa_n q^n encode modular forms in coefficients and feed Hecke/L-function constructions."
        },
        {
          "id": "petersson-inner-product",
          "title": "Petersson inner product",
          "anchor": "petersson",
          "prereqs": [
            "q-expansions-mf"
          ],
          "blurb": "The Petersson product ⟨f,g⟩=∫_{Γ\\H} f(τ)·conj(g(τ))·y^{k−2} dx dy turns S_k into a Hilbert space where Hecke eigenforms are orthogonal."
        }
      ]
    },
